+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export interface StackFrame {
+  raw: string;
+}
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function shouldStrip(line: string, options: NormalizedErrorStackOptions): boolean {
+  const node = options.stripInternalFrames === 'node' || options.stripInternalFrames === 'node_and_superjson';
+  const superjson = options.stripInternalFrames === 'superjson' || options.stripInternalFrames === 'node_and_superjson';
+  return (node && line.includes('node:internal')) ||
+    (superjson && /src\\/(?:transformer|plainer|index)\\.ts/.test(line));
+}
+
+function redactLine(line: string, options: NormalizedErrorStackOptions): string {
+  if (options.redactPaths === 'strip_cwd') {
+    const cwd = typeof process === 'undefined' ? '' : process.cwd().replace(/\\\\/g, '/');
+    return cwd ? line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&'), 'g'), '') : line;
+  }
+  if (options.redactPaths === 'basename') {
+    return line.replace(/(?:[A-Za-z]:)?[\\\\/][^\\s():]+(?:[\\\\/][^\\s():]+)*/g, path => {
+      const pieces = path.split(/[\\\\/]/);
+      return pieces[pieces.length - 1];
+    });
+  }
+  return line;
+}
+
+function processLines(
+  stack: string,
+  options: NormalizedErrorStackOptions,
+  frames: boolean
+): string[] {
+  let lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\
');
+  lines = lines.map((line, index) =>
+    index > 0 && options.trimLeadingWhitespace ? line.replace(/^\\s+/, '') : line
+  );
+  if (frames) {
+    lines = [lines[0], ...lines.slice(1).filter(line => !shouldStrip(line, options))];
+    lines = lines.map(line => redactLine(line, options));
+  } else {
+    lines = lines.map(line => redactLine(line, options));
+    lines = [lines[0], ...lines.slice(1).filter(line => !shouldStrip(line, options))];
+  }
+  return options.maxStackLines === undefined ? lines : lines.slice(0, options.maxStackLines);
+}
+
+export function processStackString(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string {
+  return processLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  options: NormalizedErrorStackOptions
+): StackFrame[] {
+  return processLines(stack, options, true).map(raw => ({ raw }));
+}
