+
+function serializeConfiguredError(v: Error, superJson: SuperJSON): any {
+  return serializeErrorPlain(v, superJson, 0, new Set<Error>());
+}
+
+function serializeErrorPlain(
+  error: Error,
+  superJson: SuperJSON,
+  depth: number,
+  seen: Set<Error>
+): any {
+  const options = superJson.errorStackOptions!;
+  const matches = errorMatchesFilter(error, superJson);
+  const plain: Record<string, any> = {
+    name: error.name,
+    message: matches && options.sanitizeMessage
+      ? sanitizeMessage(error.message)
+      : error.message,
+  };
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (prop !== 'stack' && prop !== 'stackFrames' && prop !== 'cause') {
+      plain[prop] = (error as any)[prop];
+    }
+  });
+
+  if (matches && options.mode === 'string' && superJson.allowedErrorProps.includes('stack') && typeof error.stack === 'string') {
+    plain.stack = processStackString(error.stack, options);
+  }
+  if (matches && options.mode === 'frames' && superJson.allowedErrorProps.includes('stackFrames') && typeof error.stack === 'string') {
+    plain.stackFrames = processStackFrames(error.stack, options);
+  }
+
+  // AggregateError's errors are intentionally retained without changing their shape.
+  if (Array.isArray((error as any).errors)) plain.errors = (error as any).errors;
+
+  const cause = (error as any).cause;
+  const canIncludeCause =
+    cause instanceof Error &&
+    !seen.has(cause) &&
+    (options.includeCauses === 'direct'
+      ? depth === 0
+      : options.includeCauses === 'deep' && depth < options.maxCauseDepth);
+  if (canIncludeCause) {
+    const nextSeen = new Set(seen);
+    nextSeen.add(error);
+    plain.cause = serializeErrorPlain(cause, superJson, depth + 1, nextSeen);
+  }
+
+  return superJson.errorClassRegistry.getProcessor(error.name)?.(plain) ?? plain;
+}
